-- nitpick mode on --

I'm not a big fan for a long if statement, this would look much nicer the other way around:

```
ffunc (c *Configurer) manageStorageAdapter() {
	newStorageAdapterType, err := c.getEtcd("/storageAdapterType", "file")
	if err != nil {
		log.Println("configurer: Error retrieving storage adapter type from etcd.  Skipping.", err)
		return
	}
	if newStorageAdapterType == c.currentStorageAdapterType {
		return
	}
	newStorageAdapter, err := storage.NewAdapter(newStorageAdapterType)
	if err != nil {
		log.Println("configurer: Error creating new storage adapter.  Skipping.", err)
		return
	}
	c.syslogishServer.SetStorageAdapter(newStorageAdapter)
	c.currentStorageAdapterType = newStorageAdapterType
	log.Printf("configurer: Activated new storage adapter: %s", newStorageAdapterType)
}
```

-- nitpick mode off --

If you just need the first `f` to work instead of the last:
```python
for f in self.dirs[root_as_posix]:
    if f['name'] == path_as_posix:
        f = to_return
        break
else:
    self.dirs[root_as_posix].append(to_return)
```
And if you do need the last one, then simply pass `self.dirs[root_as_prefix]` through `reversed()`.

I'd rather be explicit here than not. We can even do:

```py
for name in node.names:
    if not name.asname:
        continue
    asname = name.asname
    original_name = name.name
    err_kwargs = {'name': original_name, 'asname': asname}
    if self.check_upper(original_name):
        if not self.check_upper(asname):
            yield.self.err(node, 'N811', **err_kwargs)
    # ... etc ...
```

